mapper.select:
select CONCAT(CONVERT(varchar(10), a.move_stock_date, 23), ' - ', a.seq) AS moveStockDateSeq ,d.storage_name as src_storage_name ,e.storage_name as tar_storage_name , CASE WHEN COUNT(DISTINCT CASE WHEN type_cd = 'Q' THEN r.item_cd ELSE b.item_cd END) = 1 THEN MIN(CASE WHEN type_cd = 'Q' THEN c1.item_name ELSE c.item_name END) ELSE CONCAT(MIN(CASE WHEN type_cd = 'Q' THEN c1.item_name ELSE c.item_name END),' 외 ',COUNT(DISTINCT CASE WHEN type_cd = 'Q' THEN r.item_cd ELSE b.item_cd END) - 1,'건' ) END AS item_name ,isnull(sum(b.qty), 0) as qty ,isnull(sum(r.qty), 0) as reqQty ,f.member_nm as manager_name ,isnull(a.confirm_status, 'W') as confirm_status ,a.move_status ,a.move_stock_id from tb_move_stock_mst a left join tb_move_stock_item b on a.move_stock_id = b.move_stock_id left join tb_move_req_item r on a.move_stock_id = r.move_stock_id left join tb_item_mst c on c.item_cd = b.item_cd left join tb_item_mst c1 on c1.item_cd = r.item_cd inner join tb_storage_mst d on d.storage_cd = a.src_storage_cd inner join tb_storage_mst e on e.storage_cd = a.tar_storage_cd inner join tb_users f on f.user_id = a.manager_id WHERE a.move_stock_date BETWEEN #{strDate} AND #{endDate}
AND a.move_status = #{moveStatus}
AND a.src_storage_cd = #{srcStorageCd}
AND a.tar_storage_cd = #{tarStorageCd}
AND c.item_cd LIKE '%' + #{itemCd} + '%'
AND c.item_name LIKE '%' + #{itemName} + '%'
GROUP BY a.move_stock_date, a.seq, d.storage_name, e.storage_name, f.member_nm ,a.move_status,a.move_stock_id, a.confirm_status ORDER BY a.move_stock_date desc, a.seq desc

mapper.update:
update tb_move_stock_mst
set    manager_id  = #{managerId}
      ,area_cd     = dbo.getStorageByAreaCd(#{srcStorageCd})
      ,src_storage_cd = #{srcStorageCd}
      ,tar_storage_cd = #{tarStorageCd}
      ,confirmer_id     = #{confirmerId}
      ,etc              = #{etc}
      ,confirm_status   = #{confirmStatus}
      ,upd_id           = #{userId}
      ,upd_dt           = getdate()
where  move_stock_id    = #{moveStockId}

UPDATE tb_move_stock_item
SET item_type_cd = #{itemTypeCd}
  , item_cd      = #{itemCd}
  , test_no      = #{testNo}
  , qty          = #{qty}
  , upd_id       = #{userId}
  , upd_dt       = GETDATE()
where move_stock_item_id = #{moveStockItemId}

update tb_move_stock_mst
set    confirmer_id     = #{confirmerId}
      ,etc              = #{etc}
      ,move_status      = #{moveStatus}
      ,confirm_status   = #{confirmStatus}
      ,upd_id           = #{userId}
      ,upd_dt           = getdate()
where  move_stock_id    = #{moveStockId}

update tb_move_stock_mst
set    tran_id  = #{tranId}
      ,upd_id   = #{userId}
      ,upd_dt   = getdate()
where  move_stock_id  = #{moveStockId}
